import{_ as a,o as t,c as r,a6 as o}from"./chunks/framework.DtxWasON.js";const m=JSON.parse('{"title":"OoO Data Consumer Demo","description":"","frontmatter":{},"headers":[],"relativePath":"ooo/api/examples/DemoConsumer2.md","filePath":"ooo/api/examples/DemoConsumer2.md"}'),n={name:"ooo/api/examples/DemoConsumer2.md"};function i(s,e,d,u,l,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="ooo-data-consumer-demo" tabindex="-1">OoO Data Consumer Demo <a class="header-anchor" href="#ooo-data-consumer-demo" aria-label="Permalink to &quot;OoO Data Consumer Demo&quot;">​</a></h1><p>Note the &quot;is ConsumerBase&quot;, to extend <a href="https://github.com/unification-com/xfund-router/blob/main/contracts/lib/ConsumerBase.sol" target="_blank" rel="noreferrer">https://github.com/unification-com/xfund-router/blob/main/contracts/lib/ConsumerBase.sol</a> ConsumerBase.sol interacts with the deployed Router.sol smart contract which will route data requests and fee payment to the selected provider and handle data fulfilment.</p><p>The selected provider will listen to the Router for requests, then send the data back to the Router, which will in turn forward the data to your smart contract after verifying the source of the data.</p><h2 id="functions" tabindex="-1">Functions: <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions:&quot;">​</a></h2><ul><li><a href="#DemoConsumer2-constructor-address-address-address-uint256-"><code>constructor(address _router, address _xfund, address _provider, uint256 _fee) public</code></a></li><li><a href="#DemoConsumer2-setProvider-address-"><code>setProvider(address _provider) external</code></a></li><li><a href="#DemoConsumer2-setFee-uint256-"><code>setFee(uint256 _fee) external</code></a></li><li><a href="#DemoConsumer2-requestData-bytes32-string-"><code>requestData(bytes32 _data, string pair) external</code></a></li><li><a href="#DemoConsumer2-getPrice-string-"><code>getPrice(string pair) external</code></a></li><li><a href="#DemoConsumer2-increaseRouterAllowance-uint256-"><code>increaseRouterAllowance(uint256 _amount) external</code></a></li><li><a href="#DemoConsumer2-setRouter-address-"><code>setRouter(address _router) external</code></a></li><li><a href="#DemoConsumer2-withdrawxFund-address-uint256-"><code>withdrawxFund(address _to, uint256 _value) external</code></a></li><li><a href="#DemoConsumer2-receiveData-uint256-bytes32-"><code>receiveData(uint256 _price, bytes32 _requestId) internal</code></a></li></ul><p><a name="DemoConsumer2-constructor-address-address-address-uint256-"></a></p><h3 id="function-constructor-address-router-address-xfund-address-provider-uint256-fee-public" tabindex="-1">Function <code>constructor(address _router, address _xfund, address _provider, uint256 _fee) public </code> <a class="header-anchor" href="#function-constructor-address-router-address-xfund-address-provider-uint256-fee-public" aria-label="Permalink to &quot;Function `constructor(address _router, address _xfund, address _provider, uint256 _fee) public `&quot;">​</a></h3><p>constructor must pass the address of the Router and xFUND smart contracts to the constructor of your contract! Without it, this contract cannot interact with the system, nor request/receive any data. The constructor calls the parent ConsumerBase constructor to set these.</p><h4 id="parameters" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h4><ul><li><p><code>_router</code>: address of the Router smart contract</p></li><li><p><code>_xfund</code>: address of the xFUND smart contract</p></li><li><p><code>_provider</code>: address of the default provider</p></li><li><p><code>_fee</code>: uint256 default fee <a name="DemoConsumer2-setProvider-address-"></a></p></li></ul><h3 id="function-setprovider-address-provider-external" tabindex="-1">Function <code>setProvider(address _provider) external </code> <a class="header-anchor" href="#function-setprovider-address-provider-external" aria-label="Permalink to &quot;Function `setProvider(address _provider) external `&quot;">​</a></h3><p>setProvider change default provider. Uses OpenZeppelin&#39;s onlyOwner modifier to secure the function.</p><h4 id="parameters-1" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h4><ul><li><code>_provider</code>: address of the default provider <a name="DemoConsumer2-setFee-uint256-"></a></li></ul><h3 id="function-setfee-uint256-fee-external" tabindex="-1">Function <code>setFee(uint256 _fee) external </code> <a class="header-anchor" href="#function-setfee-uint256-fee-external" aria-label="Permalink to &quot;Function `setFee(uint256 _fee) external `&quot;">​</a></h3><p>setFee change default fee. Uses OpenZeppelin&#39;s onlyOwner modifier to secure the function.</p><h4 id="parameters-2" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h4><ul><li><code>_fee</code>: uint256 default fee <a name="DemoConsumer2-requestData-bytes32-string-"></a></li></ul><h3 id="function-requestdata-bytes32-data-string-pair-external" tabindex="-1">Function <code>requestData(bytes32 _data, string pair) external </code> <a class="header-anchor" href="#function-requestdata-bytes32-data-string-pair-external" aria-label="Permalink to &quot;Function `requestData(bytes32 _data, string pair) external `&quot;">​</a></h3><p>getData the actual function to request data.</p><p>NOTE: Calls ConsumerBase.sol&#39;s requestData function.</p><p>Uses OpenZeppelin&#39;s onlyOwner modifier to secure the function. The data format can be found at <a href="https://docs.unification.io/ooo/guide/ooo_api.html" target="_blank" rel="noreferrer">https://docs.unification.io/ooo/guide/ooo_api.html</a> Endpoints should be Hex encoded using, for example the web3.utils.asciiToHex function.</p><h4 id="parameters-3" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h4><ul><li><code>_data</code>: bytes32 data being requested. <a name="DemoConsumer2-getPrice-string-"></a></li></ul><h3 id="function-getprice-string-pair-external-uint256" tabindex="-1">Function <code>getPrice(string pair) external -&gt; uint256</code> <a class="header-anchor" href="#function-getprice-string-pair-external-uint256" aria-label="Permalink to &quot;Function `getPrice(string pair) external  -&gt; uint256`&quot;">​</a></h3><p>getPrice returns the current price</p><h4 id="return-values" tabindex="-1">Return Values: <a class="header-anchor" href="#return-values" aria-label="Permalink to &quot;Return Values:&quot;">​</a></h4><ul><li>price uint256 <a name="DemoConsumer2-increaseRouterAllowance-uint256-"></a></li></ul><h3 id="function-increaserouterallowance-uint256-amount-external" tabindex="-1">Function <code>increaseRouterAllowance(uint256 _amount) external </code> <a class="header-anchor" href="#function-increaserouterallowance-uint256-amount-external" aria-label="Permalink to &quot;Function `increaseRouterAllowance(uint256 _amount) external `&quot;">​</a></h3><p>increaseRouterAllowance allows the Router to spend xFUND on behalf of this smart contract.</p><p>NOTE: Calls the internal _increaseRouterAllowance function in ConsumerBase.sol.</p><p>Required so that xFUND fees can be paid. Uses OpenZeppelin&#39;s onlyOwner modifier to secure the function.</p><h4 id="parameters-4" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-4" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h4><ul><li><code>_amount</code>: uint256 amount to increase <a name="DemoConsumer2-setRouter-address-"></a></li></ul><h3 id="function-setrouter-address-router-external" tabindex="-1">Function <code>setRouter(address _router) external </code> <a class="header-anchor" href="#function-setrouter-address-router-external" aria-label="Permalink to &quot;Function `setRouter(address _router) external `&quot;">​</a></h3><p>setRouter allows updating the Router contract address</p><p>NOTE: Calls the internal setRouter function in ConsumerBase.sol.</p><p>Can be used if network upgrades require new Router deployments. Uses OpenZeppelin&#39;s onlyOwner modifier to secure the function.</p><h4 id="parameters-5" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-5" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h4><ul><li><code>_router</code>: address new Router address <a name="DemoConsumer2-withdrawxFund-address-uint256-"></a></li></ul><h3 id="function-withdrawxfund-address-to-uint256-value-external" tabindex="-1">Function <code>withdrawxFund(address _to, uint256 _value) external </code> <a class="header-anchor" href="#function-withdrawxfund-address-to-uint256-value-external" aria-label="Permalink to &quot;Function `withdrawxFund(address _to, uint256 _value) external `&quot;">​</a></h3><p>increaseRouterAllowance allows contract owner to withdraw any xFUND held in this contract. Uses OpenZeppelin&#39;s onlyOwner modifier to secure the function.</p><h4 id="parameters-6" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-6" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h4><ul><li><p><code>_to</code>: address recipient</p></li><li><p><code>_value</code>: uint256 amount to withdraw <a name="DemoConsumer2-receiveData-uint256-bytes32-"></a></p></li></ul><h3 id="function-receivedata-uint256-price-bytes32-requestid-internal" tabindex="-1">Function <code>receiveData(uint256 _price, bytes32 _requestId) internal </code> <a class="header-anchor" href="#function-receivedata-uint256-price-bytes32-requestid-internal" aria-label="Permalink to &quot;Function `receiveData(uint256 _price, bytes32 _requestId) internal `&quot;">​</a></h3><p>recieveData - example end user function to receive data. This will be called by the data provider, via the Router&#39;s fulfillRequest, and through the ConsumerBase&#39;s rawReceiveData function.</p><p>Note: validation of the data and data provider sending the data is handled by the Router smart contract prior to it forwarding the data to your contract, allowing devs to focus on pure functionality. ConsumerBase.sol&#39;s rawReceiveData function can only be called by the Router smart contract.</p><h4 id="parameters-7" tabindex="-1">Parameters: <a class="header-anchor" href="#parameters-7" aria-label="Permalink to &quot;Parameters:&quot;">​</a></h4><ul><li><p><code>_price</code>: uint256 result being sent</p></li><li><p><code>_requestId</code>: bytes32 request ID of the request being fulfilled</p></li></ul>',49)])])}const p=a(n,[["render",i]]);export{m as __pageData,p as default};
